def build_request(system, turns):
    msgs = []
    for i, text in enumerate(turns):
        role = "user" if i % 2 == 0 else "assistant"
        msgs.append({"role": role, "content": text})
    return {"model": "claude-sonnet-4-5",
            "max_tokens": 1024,
            "system": system,
            "messages": msgs}
